diff --git a/src/util/title-case.ts b/src/util/title-case.ts
+export function titleCase(input: string): string {
+  return input.split(/\s+/).map(w => w ? w[0].toUpperCase() + w.slice(1) : w).join(' ');
+}
diff --git a/src/util/title-case.test.ts b/src/util/title-case.test.ts
+test('capitalizes each word', () => expect(titleCase('hello world')).toBe('Hello World'));
